#include<bits/stdc++.h>
using namespace std;
const long long N=100010,M=300010,B=21;
long long n,m,fa[N][B],d[N],fa_bcj[N],lg[N],MSTsum;
vector<pair<long long,long long>> mp[N];
map<pair<long long,pair<long long,long long>>,long long> id;
bool inMST[M];
long long find(long long x)
{
    return(x==fa_bcj[x]?x:fa_bcj[x]=find(fa_bcj[x]));
}
struct edge
{
    int u,v,w;
    bool operator<(const edge&b)const
    {
        return w<b.w;
    }
}e[M];
struct node
{
    long long max1,max2;
    node()
    {
        max1=-1e18;
        max2=-1e18;
    }
    node operator+(const node&b)const
    {
        node ans;
        if(max1==b.max1)
        {
            ans.max1=max1;
            ans.max2=max(max2,b.max2);
        }
        else
        {
            ans.max1=max(max1,b.max1);
            ans.max2=max({min(max1,b.max1),max2,b.max2});
        }
        return ans;
    }
}max1[N][B];
void dfs(long long x,long long f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(long long i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
        max1[x][i]=max1[x][i-1]+max1[fa[x][i-1]][i-1];
    }
    for(auto j:mp[x])
    {
        long long v=j.first,val=j.second;
        if(v!=f)
        {
            max1[v][0].max1=val;
            dfs(v,x);
        }
    }
}
node getmax(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    node ans;
    while(d[x]>d[y])
    {
        ans=ans+max1[x][lg[d[x]-d[y]]];
        x=fa[x][lg[d[x]-d[y]]];
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            ans=ans+max1[x][i];
            ans=ans+max1[y][i];
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    ans=ans+max1[x][0];
    ans=ans+max1[y][0];
    x=fa[x][0];
    y=fa[y][0];
    return ans;
}
void kruskal()
{
    sort(e+1,e+1+m);
    for(long long i=1;i<=n;i++)
    {
        fa_bcj[i]=i;
    }
    for(long long i=1;i<=m;i++)
    {
        long long u=e[i].u,v=e[i].v,w=e[i].w;
        long long a=find(u),b=find(v);
        if(a!=b)
        {
            fa_bcj[a]=b;
            mp[u].push_back({v,w});
            mp[v].push_back({u,w});
            MSTsum+=w;
            inMST[i]=true;
        }
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld%lld",&e[i].u,&e[i].v,&e[i].w);
        if(e[i].u>e[i].v)
        {
            swap(e[i].u,e[i].v);
        }
        if(e[i].u==e[i].v)
        {
            i--;
            m--;
            continue;
        }
        if(id[{e[i].u,{e[i].v,e[i].w}}])
        {
            i--;
            m--;
            continue;
        }
        id[{e[i].u,{e[i].v,e[i].w}}]=i;
    }
    kruskal();
    dfs(1);
    long long ans=1e18;
    for(long long i=1;i<=m;i++)
    {
        if(!inMST[i])
        {
            node tmp=getmax(e[i].u,e[i].v);
            long long val=tmp.max1;
            if(e[i].w==val)
            {
                val=tmp.max2;
            }
            if(e[i].w<val)
            {
                continue;
            }
            ans=min(ans,MSTsum-val+e[i].w);
        }
    }
    printf("%lld",ans);
    return 0;
}
